content.text:
// BEM in SCSS — use & for concatenation
.card {
  border-radius: 8px;
  background: var(--color-surface);

  &__image   { width: 100%; aspect-ratio: 16/9; object-fit: cover; }
  &__body    { padding: 1rem; }
  &__title   { font-size: 1.25rem; font-weight: 700;
    &--truncated { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  }
  &__excerpt { color: var(--color-text-muted); line-height: 1.6; }
  &__footer  { padding: 0.75rem 1rem; border-top: 1px solid var(--color-border); }

  &--dark { background: var(--color-surface-dark); color: var(--color-text-inverse); }
}

// src/app/ui/card/card.component.scss
:host {             // maps to the .card block
  display: block;
  border-radius: 8px;
  background: var(--color-surface);
}

// Elements — no need to prefix with .card because ViewEncapsulation
// scopes these to the component automatically
.card__image   { ... }
.card__title   { ... }
.card__body    { ... }

// Modifiers on :host via @HostBinding or input-driven class
:host(.card--loading) { opacity: 0.6; pointer-events: none; }

// card.component.ts
@Component({ selector: 'app-card', ... })
export class CardComponent {
  @Input() loading = false;
  @HostBinding('class.card--loading') get isLoading() { return this.loading; }
}

// OOCSS: structure object
.btn {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.5rem 1.25rem;
  border-radius: 6px;
  border: 2px solid transparent;
  font-size: 0.875rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 150ms, color 150ms, border-color 150ms;
}

// OOCSS: skin variants — visual only, no layout
.btn-primary   { background: var(--color-primary); color: #fff; border-color: var(--color-primary); }
.btn-secondary { background: transparent; color: var(--color-primary); border-color: var(--color-primary); }
.btn-ghost     { background: transparent; color: var(--color-text); border-color: var(--color-border); }

// OOCSS: size modifiers (structure, not skin)
.btn-sm { padding: 0.25rem 0.75rem; font-size: 0.75rem; }
.btn-lg { padding: 0.75rem 2rem;   font-size: 1rem; }

// src/styles.scss — global ITCSS entry point
@use 'settings/tokens';      // layer 1 — CSS custom properties
@use 'settings/breakpoints'; // layer 1 — SCSS maps
@use 'tools/mixins';         // layer 2 — respond-to(), etc.
@use 'generic/reset';        // layer 3 — box-sizing, margins
@use 'generic/normalize';    // layer 3
@use 'elements/base';        // layer 4 — html, body, a, img
// layers 5-6 are loaded per-component via styleUrls
@use 'utilities/helpers';    // layer 7 — loaded last, highest priority

// tailwind.config.js
module.exports = {
  content: ['./src/**/*.{html,ts}'],   // purge template files
  theme: { extend: {} },
  plugins: [],
}

// Bad — modifier describes visual property, not behaviour/state
.btn--red { background: red; }
.btn--big { font-size: 1.5rem; padding: 1rem; }

// Good — modifier describes semantic meaning or state
.btn--danger   { background: var(--color-danger); }
.btn--lg       { font-size: 1.25rem; padding: 0.875rem 2rem; }
.btn--loading  { opacity: 0.6; pointer-events: none; }
.btn--disabled { cursor: not-allowed; opacity: 0.4; }

// Bad — ties .card appearance to sidebar context
.sidebar .card { font-size: 0.875rem; border: none; }

// Good — use a modifier
.card--compact { font-size: 0.875rem; }
// In Angular, drive via @Input
// <app-card [compact]="inSidebar" />
// @HostBinding('class.card--compact') get isCompact() { return this.compact; }

// Bad — jQuery-era state classes mix with BEM
.active    { ... }
.is-open   { ... }
.disabled  { ... }

// Good — SMACSS-style state or BEM modifier, applied consistently
.nav__item--active  { ... }
.dropdown--open     { ... }
.btn--disabled      { cursor: not-allowed; }

// In Angular — use HostBinding for BEM modifiers on the host
@HostBinding('class.nav__item--active')
get isActive() { return this.router.isActive(this.href, false); }
